values
  ('12020000-0000-0000-0000-000000000001', '12000000-0000-0000-0001-000000000002', null,
insert into standard_items
  (id, standard_section_id, parent_item_id, number, text, position)
values
  ('fe2cb490-5d7d-5d80-bf81-4e4085c86f36', '12000000-0000-0000-0001-000000000003', null, '12.3.1', 'Os circuitos elétricos de comando e potência das máquinas e equipamentos devem ser projetados e mantidos de modo a prevenir, por meios seguros, os perigos de choque elétrico, incêndio, explosão e outros tipos de acidentes, conforme previsto nas normas técnicas oficiais e, na falta dessas, nas normas internacionais aplicáveis.', 1),
  ('20ef5461-06f6-5937-ba02-acc098f9fcba', '12000000-0000-0000-0001-000000000003', null, '12.3.2', 'Devem ser aterradas, conforme as normas técnicas oficiais vigentes, as carcaças, invólucros, blindagens ou partes condutoras das máquinas e equipamentos que não façam parte dos circuitos elétricos, mas que possam ficar sob tensão.', 2),
  ('7e3d3412-b59f-57e6-b42c-33d4cdd0db3f', '12000000-0000-0000-0001-000000000003', null, '12.3.3', 'Os circuitos elétricos de comando e potência das máquinas e equipamentos que estejam ou possam estar em contato direto ou indireto com água ou agentes corrosivos devem ser projetadas com meios e dispositivos que garantam sua blindagem, estanqueidade, isolamento e aterramento, de modo a prevenir a ocorrência de acidentes.', 3),
  ('0d0c84b5-9d57-5548-a255-dc9100087928', '12000000-0000-0000-0001-000000000003', null, '12.3.4', 'Os condutores de alimentação elétrica das máquinas e equipamentos devem atender aos seguintes requisitos mínimos de segurança: a) oferecer resistência mecânica compatível com a sua utilização; b) possuir proteção contra a possibilidade de rompimento mecânico, de contatos abrasivos e de contato com lubrificantes, combustíveis e calor; c) localização de forma que nenhum segmento fique em contato com as partes móveis ou cantos vivos; d) não dificultar o trânsito de pessoas e materiais ou a operação das máquinas; e) não oferecer quaisquer outros tipos de riscos na sua localização; e f) ser constituídos de materiais que não propaguem o fogo.', 4),
  ('088a37fd-d52f-5415-abc1-9856d8056041', '12000000-0000-0000-0001-000000000003', null, '12.3.5', 'Os quadros ou painéis de comando e potência das máquinas e equipamentos devem atender aos seguintes requisitos mínimos de segurança: a) possuir porta de acesso mantida permanentemente fechada, exceto nas situações de manutenção, pesquisa de defeitos e outras intervenções, devendo ser observadas as condições previstas nas normas técnicas oficiais ou nas normas internacionais aplicáveis; b) possuir sinalização quanto ao perigo de choque elétrico e restrição de acesso por pessoas não autorizadas; c) ser mantidos em bom estado de conservação, limpos e livres de objetos e ferramentas; d) possuir proteção e identificação dos circuitos; e e) observar ao grau de proteção adequado em função do ambiente de uso.', 5),
  ('b3b5d7a2-5cc8-5721-89fb-7ff0cdd5470e', '12000000-0000-0000-0001-000000000003', null, '12.3.6', 'As ligações e derivações dos condutores elétricos das máquinas e equipamentos devem ser feitas mediante dispositivos apropriados e conforme as normas técnicas oficiais vigentes, de modo a assegurar resistência mecânica e contato elétrico adequado, com características equivalentes aos condutores elétricos utilizados e proteção contra riscos.', 6),
  ('109881b6-56b1-5653-ba2c-364ef89d9f96', '12000000-0000-0000-0001-000000000003', null, '12.3.7', 'As instalações elétricas das máquinas e equipamentos que utilizem energia elétrica fornecida por fonte externa devem possuir dispositivo protetor contra sobrecorrente, dimensionado conforme a demanda de consumo do circuito.', 7),
  ('89b7e571-5ba2-5ebf-b7af-fc36e694d004', '12000000-0000-0000-0001-000000000003', '109881b6-56b1-5653-ba2c-364ef89d9f96', '12.3.7.1', 'As máquinas e equipamentos devem possuir dispositivo protetor contra sobretensão quando a elevação da tensão puder ocasionar risco de acidentes.', 8),
  ('f55c4702-f12b-5013-80a2-51f01a474e34', '12000000-0000-0000-0001-000000000003', '109881b6-56b1-5653-ba2c-364ef89d9f96', '12.3.7.2', 'Nas máquinas e equipamentos em que a falta ou a inversão de fases da alimentação elétrica puder ocasionar riscos, deve haver dispositivo que impeça a ocorrência de acidentes.', 9),
  ('4c5a4af0-1735-5ab4-bafe-82cf74f5d79f', '12000000-0000-0000-0001-000000000003', null, '12.3.8', 'São proibidas nas máquinas e equipamentos: a) a utilização de chave geral como dispositivo de partida e parada; b) a utilização de chaves tipo faca nos circuitos elétricos; e c) a existência de partes energizadas expostas de circuitos que utilizam energia elétrica.', 10),
  ('f451f2be-64da-5ec4-a598-c300089e558c', '12000000-0000-0000-0001-000000000003', null, '12.3.9', 'As baterias devem atender aos seguintes requisitos mínimos de segurança: a) localização de modo que sua manutenção e troca possam ser realizadas facilmente a partir do solo ou de uma plataforma de apoio; b) constituição e fixação de forma a não haver deslocamento acidental; e c) proteção do terminal positivo, a fim de prevenir contato acidental e curto-circuito.', 11),
  ('2983a799-d591-5fd4-93b3-fce2538e25f5', '12000000-0000-0000-0001-000000000003', null, '12.3.10', 'Os serviços e substituições de baterias devem ser realizados conforme indicação constante do manual de operação.', 12),
  ('58a6fffa-66af-5f61-aebc-442255097600', '12000000-0000-0000-0001-000000000004', null, '12.4.1', 'Os dispositivos de partida, acionamento e parada das máquinas devem ser projetados, selecionados e instalados de modo que: a) não se localizem em suas zonas perigosas; b) possam ser acionados ou desligados em caso de emergência por outra pessoa que não seja o operador; c) impeçam acionamento ou desligamento involuntário pelo operador ou por qualquer outra forma acidental; d) não acarretem riscos adicionais; e e) dificulte-se a burla.', 13),
  ('944ae109-faad-5b96-8bfe-bfdf14a4db98', '12000000-0000-0000-0001-000000000004', null, '12.4.2', 'Os comandos de partida ou acionamento das máquinas devem possuir dispositivos que impeçam seu funcionamento automático ao serem energizadas.', 14),
  ('67525127-48e5-53a7-a9fa-146d644f5e3a', '12000000-0000-0000-0001-000000000004', null, '12.4.3', 'Quando forem utilizados dispositivos de acionamento bimanual, visando a manter as mãos do operador fora da zona de perigo, esses devem atender aos seguintes requisitos mínimos do comando: a) possuir atuação síncrona, ou seja, um sinal de saída deve ser gerado somente quando os dois dispositivos de atuação do comando - botões - forem atuados com um retardo de tempo menor ou igual a 0,5 s (meio segundo); b) estar sob monitoramento automático por interface de segurança, se indicado pela apreciação de risco; c) ter relação entre os sinais de entrada e saída, de modo que os sinais de entrada aplicados a cada um dos dois dispositivos de atuação devem juntos se iniciar e manter o sinal de saída somente durante a aplicação dos dois sinais; d) o sinal de saída deve terminar quando houver desacionamento de qualquer dos dispositivos de atuação; e) possuir dispositivos de atuação que exijam intenção do operador em acioná-los a fim de minimizar a probabilidade de acionamento acidental; f) possuir distanciamento, barreiras ou o utra solução prevista nas normas técnicas oficiais ou nas normas internacionais aplicáveis entre os dispositivos de atuação para dificultar a burla do efeito de proteção; e g) tornar possível o reinício do sinal de saída somente após a desativação dos dois dispositivos de atuação.', 15),
  ('f9db55b1-ec5d-5b0f-abe3-44684e03d032', '12000000-0000-0000-0001-000000000004', null, '12.4.4', 'Nas máquinas e equipamentos operados por dois ou mais dispositivos de acionamento bimanual, a atuação síncrona é requerida somente para cada um dos dispositivos de acionamento bimanual e não entre dispositivos diferentes, que devem manter simultaneidade entre si.', 16),
  ('b93a7dbc-e057-5723-9baa-fd8f0e786d6a', '12000000-0000-0000-0001-000000000004', null, '12.4.5', 'Os dispositivos de acionamento bimanual devem ser posicionados a uma distância segura da zona de perigo, levando em consideração: a) a forma, a disposição e o tempo de resposta do dispositivo de acionamento bimanual; b) o tempo máximo necessário para a paralisação da máquina ou para a remoção do perigo, após o término do sinal de saída do dispositivo de acionamento bimanual; e c) a utilização projetada para a máquina.', 17),
  ('6d87a5bc-e030-5851-9ab7-0d3fc74ba17c', '12000000-0000-0000-0001-000000000004', null, '12.4.6', 'Os dispositivos de acionamento bimanual móveis instalados em pedestais devem: a) manter-se estáveis em sua posição de trabalho; e b) possuir altura compatível com o alcance do operador em sua posição de trabalho.', 18),
  ('1d81d326-b289-5d59-b7a5-33058ae4aad1', '12000000-0000-0000-0001-000000000004', null, '12.4.7', 'Nas máquinas e equipamentos cuja operação requeira a participação de mais de uma pessoa, o número de dispositivos de acionamento bimanual simultâneos deve corresponder ao número de operadores expostos aos perigos decorrentes de seu acionamento, de modo que o nível de proteção seja o mesmo para cada trabalhador.', 19),
  ('a9b8e4e9-51ff-5878-8358-34c72bfbdd50', '12000000-0000-0000-0001-000000000004', '1d81d326-b289-5d59-b7a5-33058ae4aad1', '12.4.7.1', 'Deve haver seletor do número de dispositivos de acionamento em utilização, com bloqueio que impeça a sua seleção por pessoas não autorizadas.', 20),
  ('acd8f4fc-e8d2-58a5-8372-01cfd14b2578', '12000000-0000-0000-0001-000000000004', '1d81d326-b289-5d59-b7a5-33058ae4aad1', '12.4.7.2', 'O circuito de acionamento deve ser projetado de modo a impedir o funcionamento dos dispositivos de acionamento bimanual habilitados pelo seletor enquanto os demais dispositivos de acionamento bimanuais não habilitados não forem desconectados.', 21),
  ('1ca887a7-6196-58c6-9ba3-8ecdbb97f9f8', '12000000-0000-0000-0001-000000000004', '1d81d326-b289-5d59-b7a5-33058ae4aad1', '12.4.7.3', 'Quando utilizados dois ou mais dispositivos de acionamento bimanual simultâneos, devem possuir sinal luminoso que indique seu funcionamento.', 22),
  ('ac4eb0bf-a45b-5847-a6c0-49b770c970da', '12000000-0000-0000-0001-000000000004', null, '12.4.8', 'As máquinas ou equipamentos concebidos e fabricados para permitir a utilização de vários modos de comando ou de funcionamento que apresentem níveis de segurança diferentes devem possuir um seletor que atenda aos seguintes requisitos: a) possibilidade de bloqueio em cada posição, impedindo a sua mudança por pessoas não autorizadas; b) correspondência de cada posição a um único modo de comando ou de funcionamento; c) modo de comando selecionado com prioridade sobre todos os outros sistemas de comando, com exceção da parada de emergência; e d) a seleção deve ser visível, clara e facilmente identificável.', 23),
  ('ac2f621c-2169-5911-9f70-eddfea47c345', '12000000-0000-0000-0001-000000000004', null, '12.4.9', 'As máquinas e equipamentos, cujo acionamento por pessoas não autorizadas possam oferecer risco à saúde ou integridade física de qualquer pessoa, devem possuir sistema que possibilite o bloqueio de seus dispositivos de acionamento.', 24),
  ('8a46888a-374a-52c1-a506-9f76e6e63371', '12000000-0000-0000-0001-000000000004', null, '12.4.10', 'O acionamento e o desligamento simultâneo por um único comando de um conjunto de máquinas e equipamentos ou de máquinas e equipamentos de grande dimensão devem ser precedidos da emissão de sinal sonoro ou visual.', 25),
  ('e8fbb378-4410-5eda-9bac-0785c62a4fe9', '12000000-0000-0000-0001-000000000004', null, '12.4.11', 'Devem ser adotadas, quando necessárias, medidas adicionais de alerta, como sinal visual e dispositivos de telecomunicação, considerando as características do processo produtivo e dos trabalhadores.', 26),
  ('4e633138-0e32-5f65-af7d-94c8ced2942d', '12000000-0000-0000-0001-000000000004', null, '12.4.12', 'As máquinas e equipamentos comandados por radiofrequência devem possuir proteção contra interferências eletromagnéticas acidentais.', 27),
  ('32874e37-262c-52d2-80bd-b2086e2e64ba', '12000000-0000-0000-0001-000000000004', null, '12.4.13', 'Os componentes de partida, parada, acionamento e controles que compõem a interface de operação das máquinas e equipamentos fabricados a partir de 24 de março de 2012 devem: a) possibilitar a instalação e funcionamento do sistema de parada de emergência, quando aplicável, conforme itens e subitens do capítulo sobre dispositivos de parada de emergência, desta NR; e b) operar em extrabaixa tensão de até 25VCA (vinte e cinco volts em corrente alternada) ou de até 60VCC (sessenta volts em corrente contínua).', 28),
  ('3d9f9a47-5039-51b4-833f-e74e912e6b2c', '12000000-0000-0000-0001-000000000004', '32874e37-262c-52d2-80bd-b2086e2e64ba', '12.4.13.1', 'Os componentes de partida, parada, acionamento e controles que compõem a interface de operação das máquinas e equipamentos fabricados até 24 de março de 2012 devem: a) possibilitar a instalação e funcionamento do sistema de parada de emergência, quando aplicável, conforme itens e subitens do capítulo dispos itivos de parada de emergência, desta NR; e b) quando a apreciação de risco indicar a necessidade de proteções contra choques elétricos, operar em extrabaixa tensão de até 25VCA (vinte e cinco volts em corrente alternada) ou de até 60VCC (sessenta volts em corrente contínua).', 29),
  ('661b6468-b55d-583f-96aa-ac8d57fc0110', '12000000-0000-0000-0001-000000000004', '3d9f9a47-5039-51b4-833f-e74e912e6b2c', '12.4.13.1.1', 'Poderá ser adotada outra medida de proteção contra choques elétricos, conforme normas técnicas oficiais vigentes em alternativa as alíneas "b" dos respectivos subitens 12.4.13 e 12.4.13.1 desta NR.', 30),
  ('7363cc79-2be1-55ae-92df-222fe80402e1', '12000000-0000-0000-0001-000000000004', null, '12.4.14', 'Se indicada pela apreciação de riscos a necessidade de redundância dos dispositivos responsáveis pela prevenção de partida inesperada ou pela função de parada relacionada à segurança, conforme a categoria de segurança requerida, o circuito elétrico da chave de partida de motores de máquinas e equipamentos deve: a) possuir estrutura redundante; b) permitir que as falhas que comprometem a função de segurança sejam monitoradas; e c) ser adequadamente dimensionado de acordo com o estabelecido pelas normas técnicas oficiais ou pelas normas internacionais aplicáveis.', 31),
  ('480fc362-3349-5b7c-b716-e324833113f7', '12000000-0000-0000-0001-000000000004', '7363cc79-2be1-55ae-92df-222fe80402e1', '12.4.14.1', 'É permitida a parada controlada do motor, desde que não haja riscos decorrentes de sua parada não instantânea.', 32),
  ('a3ab88ba-7105-55be-bbd3-433dd74565ce', '12000000-0000-0000-0001-000000000005', null, '12.5.1', 'As zonas de perigo das máquinas e equipamentos devem possuir sistemas de segurança, caracterizados por proteções fixas, proteções móveis e dispositivos de segurança interligados, que resguardem proteção à saúde e à integridade física dos trabalhadores.', 33),
  ('475fb6de-12f4-5203-b392-21f4cfcd1fd8', '12000000-0000-0000-0001-000000000005', 'a3ab88ba-7105-55be-bbd3-433dd74565ce', '12.5.1.1', 'Quando utilizadas proteções que restringem o acesso do corpo ou parte dele, devem ser observadas as distâncias mínimas conforme normas técnicas oficiais ou normas internacionais aplicáveis.', 34),
  ('2da1d1cc-4bd5-5bce-8e66-2dab60e308a2', '12000000-0000-0000-0001-000000000005', null, '12.5.2', 'Os sistemas de segurança devem ser selecionados e instalados de modo a atender aos seguintes requisitos: a) ter categoria de segurança conforme apreciação de riscos prevista nas normas técnicas oficiais; b) estar sob a responsabilidade técnica de profissional legalmente habilitado; c) possuir conformidade técnica com o sistema de comando a que são integrados; d) instalação de modo que dificulte a sua burla; e) manterem-se sob vigilância automática, ou seja, monitoramento, se indicado pela apreciação de risco, de acordo com a categoria de segurança requerida, exceto para dispositivos de segurança exclusivamente mecânicos; e f) paralisação dos movimentos perigosos e demais riscos quando ocorrerem falhas ou situações anormais de trabalho.', 35),
  ('bdfd862b-3a5e-57c8-9600-24f1d8a536bc', '12000000-0000-0000-0001-000000000005', '2da1d1cc-4bd5-5bce-8e66-2dab60e308a2', '12.5.2.1', 'A instalação de sistemas de segurança deve ser realizada por profissional legalmente habilitado ou profissional qualificado ou capacitado, qua ndo autorizados pela empresa.', 36),
  ('630220d9-7fbc-5b62-89c3-0d7dbb68849b', '12000000-0000-0000-0001-000000000005', null, '12.5.3', 'Os sistemas de segurança, se indicado pela apreciação de riscos, devem exigir rearme (“reset”) manual.', 37),
  ('8f584849-c488-519d-b43a-edbba05bc86a', '12000000-0000-0000-0001-000000000005', '630220d9-7fbc-5b62-89c3-0d7dbb68849b', '12.5.3.1', 'Depois que um comando de parada tiver sido iniciado pelo sistema de segurança, a condição de parada deve ser mantida até que existam condições seguras para o rearme.', 38),
  ('6a4553a3-bbdf-5616-be14-ce8d0d6ee272', '12000000-0000-0000-0001-000000000005', null, '12.5.4', 'Para fins de aplicação desta NR, considera-se proteção o elemento especificamente utilizado para prover segurança por meio de barreira física, podendo ser: a) proteção fixa, que deve ser mantida em sua posição de maneira permanente ou por meio de elementos de fixação que só permitam sua remoção ou abertura com o uso de ferramentas; b) proteção móvel, que pode ser aberta sem o uso de ferramentas, geralmente ligada por elementos mecânicos à estrutura da máquina ou a um elemento fixo próximo, e deve se associar a dispositivos de intertravamento.', 39),
  ('71e68e3c-91ef-5db3-accc-e47a41ffd0cf', '12000000-0000-0000-0001-000000000005', null, '12.5.5', 'Os componentes relacionados aos sistemas de segurança e comandos de acionamento e parada das máquinas, inclusive de emergência, devem garantir a manutenção do estado seguro da máquina ou equipamento quando ocorrerem flutuações no nível de energia além dos limites considerados no projeto, incluindo o corte e restabelecimento do fornecimento de energia.', 40),
  ('1d5d840f-fd2f-5833-8ec3-7fa3d9430a3c', '12000000-0000-0000-0001-000000000005', null, '12.5.6', 'A proteção deve ser móvel quando o acesso a uma zona de perigo for requerido mais de uma vez por turno de trabalho, observando-se que: a) a proteção deve ser associada a um dispositivo de intertravamento quando sua abertura não possibilitar o acesso à zona de perigo antes da eliminação do risco; e b) a proteção deve ser associada a um dispositivo de intertravamento com bloqueio quando sua abertura possibilitar o acesso à zona de perigo antes da eliminação do risco.', 41),
  ('8256be31-4885-5955-868a-05dc82572026', '12000000-0000-0000-0001-000000000005', '1d5d840f-fd2f-5833-8ec3-7fa3d9430a3c', '12.5.6.1', 'É permitida a ligação em série, na mesma interface de segurança, de dispositivos de intertravamento de diferentes proteções móveis, desde que observado o disposto na ISO/TR 24.119.', 42),
  ('630f8c83-20a6-554e-8186-05c24253743e', '12000000-0000-0000-0001-000000000005', null, '12.5.7', 'As máquinas e equipamentos dotados de proteções móveis associadas a dispositivos de intertravamento devem: a) operar somente quando as proteções estiverem fechadas; b) paralisar suas funções perigosas quando as proteções forem abertas durante a operação; e c) garantir que o fechamento das proteções por si só não possa dar início às funções perigosas.', 43),
  ('ed4e5f36-42bf-565c-9e0e-99196b8b2cb3', '12000000-0000-0000-0001-000000000005', '630f8c83-20a6-554e-8186-05c24253743e', '12.5.7.1', 'A utilização de proteções intertravadas com comando de partida, como exceção ao previsto na alínea “c” do subitem 12.5.7, deve ser limitada e aplicada conforme as exigências específicas previstas em normas técnicas oficiais.', 44),
  ('07b50ef8-aeda-57c2-92ae-917c4c27ad25', '12000000-0000-0000-0001-000000000005', null, '12.5.8', 'Os dispositivos de intertravamento com bloqueio associados às proteções móveis das máquinas e equipamentos devem: a) permitir a operação somente enquanto a proteção estiver fechada e bloqueada; b) manter a proteção fechada e bloqueada até que tenha sido eliminado o risco de lesão devido às funções perigosas da máquina ou do equipamento; e c) garantir que o fechamento e bloqueio da proteção por si só não possa dar início às funções perigosas da máquina ou do equipamento.', 45),
  ('31faf42a-dbb5-5e13-97eb-80ea17fd4502', '12000000-0000-0000-0001-000000000005', '07b50ef8-aeda-57c2-92ae-917c4c27ad25', '12.5.8.1', 'A utilização de proteções intertravadas com comando de partida, como exceção ao previsto na alínea “c” do subitem 12.5.8, deve ser limitada e aplicada conforme as exigências específicas previstas em normas técnicas oficiais.', 46),
  ('d654fbe8-bf74-594c-a056-9843a1439c13', '12000000-0000-0000-0001-000000000005', null, '12.5.9', 'As transmissões de força e os componentes móveis a elas interligados, acessíveis ou expostos, desde que ofereçam risco, devem possuir proteções fixas, ou móveis com dispositivos de intertravamento, que impeçam o acesso por todos os lados.', 47),
  ('7b65ade0-1d52-5435-95e0-3bba7cbb9e4c', '12000000-0000-0000-0001-000000000005', 'd654fbe8-bf74-594c-a056-9843a1439c13', '12.5.9.1', 'Quando utilizadas proteções móveis para o enclausuramento de transmissões de força que possuam inércia, devem ser utilizados dispositivos de intertravamento com bloqueio.', 48),
  ('49490903-f5c6-529e-94e3-23fde8319790', '12000000-0000-0000-0001-000000000005', 'd654fbe8-bf74-594c-a056-9843a1439c13', '12.5.9.2', 'O eixo cardã deve possuir proteção adequada, em toda a sua extensão, fixada na tomada de força da máquina, desde a cruzeta até o acoplamento do implemento ou equipamento.', 49),
  ('283dae98-659f-53f3-8ed8-0be904750363', '12000000-0000-0000-0001-000000000005', null, '12.5.10', 'As máquinas e equipamentos que ofereçam risco de ruptura de suas partes, projeção de materiais, partículas ou substâncias, devem possuir proteções que garantam a segurança e a saúde dos trabalhadores.', 50),
  ('89323726-694e-5189-a62c-0ddd71119fab', '12000000-0000-0000-0001-000000000005', null, '12.5.11', 'As proteções devem ser projetadas e construídas de modo a atender aos seguintes requisitos de segurança: a) cumprir suas funções apropriadamente durante a vida útil da máquina ou possibilitar a reposição de partes deterioradas ou danificadas; b) ser constituídas de materiais resistentes e adequados à contenção de projeção de peças, materiais e partículas; c) fixação firme e garantia de estabilidade e resistência mecânica compatíveis com os esforços requeridos; d) não criar pontos de esmagamento ou agarramento com partes da máquina ou com outras proteções; e) não possuir extremidades e arestas cortantes ou outras saliências perigosas; f) resistir às condições ambientais do local onde estão instaladas; g) dificulte-se a burla; h) proporcionar condições de higiene e limpeza; i) impedir o acesso à zona de perigo; j) ter seus dispositivos de intertravamento protegidos adequadamente contra sujidade, poeiras e corrosão, se necessário; k) ter ação positiva, ou seja, atuação de modo positivo; e l) não acarretar riscos adicionais.', 51),
  ('81802dfa-90f4-5224-aeee-e85e3a9f0d72', '12000000-0000-0000-0001-000000000005', null, '12.5.12', 'Quando a proteção for confeccionada com material descontínuo, devem ser observadas as distâncias de segurança para impedir o acesso às zonas de perigo, conforme previsto nas normas técnicas oficiais ou nas normas internacionais aplicáveis.', 52),
  ('4aa1b426-cfac-532a-8445-70002e9680e0', '12000000-0000-0000-0001-000000000005', null, '12.5.13', 'Sempre que forem utilizados sistemas de segurança, inclusive proteções distantes, com possibilidade de alguma pessoa ficar na zona de perigo, deve ser adotada uma das seguintes medidas adicionais de proteção coletiva para impedir a partida da máquina enquanto houver pessoas nessa zona: a) sensoriamento da presença de pessoas; b) proteções móveis ou sensores de segurança na entrada ou acesso à zona de perigo, associadas a rearme (“reset”) manual.', 53),
  ('4bc1be28-b0a0-5867-a0b2-9fa5c956e61e', '12000000-0000-0000-0001-000000000005', '4aa1b426-cfac-532a-8445-70002e9680e0', '12.5.13.1', 'A localização dos atuadores de rearme (“reset”) manual deve permitir uma visão completa da zona protegida pelo sistema.', 54),
  ('6031cd01-392e-5235-bc2d-d5c0b68d3e3e', '12000000-0000-0000-0001-000000000005', '4aa1b426-cfac-532a-8445-70002e9680e0', '12.5.13.2', 'Quando não for possível o cumprimento da exigência do subitem 12.5.13.1, deve ser adotado o sensoriamento da presença de pessoas nas zonas de perigo com a visualização obstruída, ou a adoção de sistema que exija a ida à zona de perigo não visualizada, como, por exemplo, duplo rearme (“reset”).', 55),
  ('cb998388-5bd6-579d-af3d-81d3d5d7ee5b', '12000000-0000-0000-0001-000000000005', '4aa1b426-cfac-532a-8445-70002e9680e0', '12.5.13.3', 'Deve haver dispositivos de parada de emergência localizados no interior da zona protegida pelo sistema, bem como meios de liberar pessoas presas dentro dela.', 56),
  ('bdc201b4-4cd5-59fc-b9c0-527a19cf97ac', '12000000-0000-0000-0001-000000000005', null, '12.5.14', 'As proteções também utilizadas como meio de acesso por exigência das características da máquina ou do equipamento devem atender aos requisitos de resistência e segurança adequados a ambas as finalidades.', 57),
  ('fdeddf8e-9203-55f0-8fe8-c457f19b97b6', '12000000-0000-0000-0001-000000000005', null, '12.5.15', 'Deve haver proteção no fundo dos degraus da escada, ou seja, nos espelhos, sempre que uma parte saliente do pé ou da mão possa contatar uma zona perigosa.', 58),
  ('0f353aef-473b-53f0-ac1e-9300d5103851', '12000000-0000-0000-0001-000000000005', null, '12.5.16', 'As proteções, dispositivos e sistemas de segurança são partes integrantes das máquinas e equipamentos e não podem ser considerados itens opcionais para qualquer fim.', 59),
  ('62383b63-6dec-5945-bfa6-3765a8a4c8c9', '12000000-0000-0000-0001-000000000005', null, '12.5.17', 'Em função do risco, poderá ser exigido projeto, diagrama ou representação esquemática dos sistemas de segurança de máquinas, com respectivas especificações técnicas em língua portuguesa, elaborado por profissional legalmente habilitado.', 60),
  ('65606b8b-5c77-5c27-aa8f-b578231d04be', '12000000-0000-0000-0001-000000000006', null, '12.6.1', 'As máquinas devem ser equipadas com um ou mais dispositivos de parada de emergência, por meio dos quais possam ser evitadas situações de perigo latentes e existentes.', 61),
  ('21e75e0f-28ac-5f7a-b913-2c6810a912c7', '12000000-0000-0000-0001-000000000006', '65606b8b-5c77-5c27-aa8f-b578231d04be', '12.6.1.1', 'Os dispositi vos de parada de emergência não devem ser utilizados como dispositivos de partida ou de acionamento.', 62),
  ('1ba740eb-a5e6-5ac2-b99e-ac74f7af5b99', '12000000-0000-0000-0001-000000000006', '65606b8b-5c77-5c27-aa8f-b578231d04be', '12.6.1.2', 'Excetuam-se da obrigação do subitem 12.6.1: a) as máquinas autopropelidas; e b) as máquinas e equipamentos nas quais o dispositivo de parada de emergência não possibilita a redução do risco.', 63),
  ('bccc0a0f-ef55-5d21-93f6-fab7eb65b8b4', '12000000-0000-0000-0001-000000000006', null, '12.6.2', 'Os dispositivos de parada de emergência devem ser posicionados em locais de fácil acesso e visualização pelos operadores em seus postos de trabalho e por outras pessoas, e mantidos permanentemente desobstruídos.', 64),
  ('bb9b7b7a-9c26-5842-8e41-4b1a56421154', '12000000-0000-0000-0001-000000000006', null, '12.6.3', 'Os dispositivos de parada de emergência devem: a) ser selecionados, montados e interconectados de forma a suportar as condições de operação previstas, bem como as influências do meio; b) ser usados como medida auxiliar, não podendo ser alternativa a medidas adequadas de proteção ou a sistemas automáticos de segurança; c) possuir acionadores projetados para fácil atuação do operador ou outros que possam necessitar da sua utilização; d) prevalecer sobre todos os outros comandos; e) provocar a parada da operação ou processo perigoso em período de tempo tão reduzido quanto tecnicamente possível, sem provocar riscos suplementares; e f) ter sua função disponível e operacional a qualquer tempo, independentemente do modo de operação;', 65),
  ('491cc7b2-3e3f-5172-9c8d-d6872f7a5583', '12000000-0000-0000-0001-000000000006', null, '12.6.4', 'A função parada de emergência não deve: a) prejudicar a eficiência de sistemas de segurança ou dispositivos com funções relacionadas com a segurança; b) prejudicar qualquer meio projetado para resgatar pessoas acidentadas; e c) gerar risco adicional.', 66),
  ('d8091d07-f13a-59d5-a3ff-c2c289d2772b', '12000000-0000-0000-0001-000000000006', null, '12.6.5', 'O acionamento do dispositivo de parada de emergência deve também resultar na retenção do acionador, de tal forma que, quando a ação no acionador for descontinuada, este se mantenha retido até que seja desacionado.', 67),
  ('0551f71d-2b3e-56a2-b065-499127e157e8', '12000000-0000-0000-0001-000000000006', 'd8091d07-f13a-59d5-a3ff-c2c289d2772b', '12.6.5.1', 'O desacionamento deve ser possível apenas como resultado de uma ação manual intencionada sobre o acionador, por meio de manobra apropriada.', 68),
  ('e8b27862-1f00-53b3-9fd2-f8d839874059', '12000000-0000-0000-0001-000000000006', null, '12.6.6', 'Quando usados acionadores do tipo cabo, deve-se: a) utilizar chaves de parada de emergência que trabalhem tracionadas, de modo a cessarem automaticamente as funções perigosas da máquina em caso de ruptura ou afrouxamento dos cabos; b) considerar o deslocamento e a força aplicada nos acionadores, necessários para a atuação das chaves de parada de emergência; e c) obedecer à distância máxima entre as chaves de parada de emergência recomendada pelo fabricante.', 69),
  ('bf707070-bea7-50ba-8bdb-4e99abad8340', '12000000-0000-0000-0001-000000000006', null, '12.6.7', 'As chaves de parada de emergência devem ser localizadas de tal forma que todo o cabo de acionamento seja visível a partir da posição de desacionamento da parada de emergência.', 70),
  ('92eed031-d810-5c6d-97cf-d90a109b1b0f', '12000000-0000-0000-0001-000000000006', 'bf707070-bea7-50ba-8bdb-4e99abad8340', '12.6.7.1', 'Se não for possível o cumprimento da exigência do subitem 12.6.7, deve -se garantir que, após a atuação e antes do desacionamento, a máquina ou equipamento seja inspecionado em toda a extensão do cabo.', 71),
  ('72f5bf3f-e40f-5720-8da1-baac0522b117', '12000000-0000-0000-0001-000000000006', null, '12.6.8', 'A parada de e mergência deve exigir rearme ou reset manual a ser realizado somente após a correção do evento que motivou o acionamento da parada de emergência.', 72),
  ('66ffb7ad-c48b-5c9d-95f0-76ea664d3e4b', '12000000-0000-0000-0001-000000000006', '72f5bf3f-e40f-5720-8da1-baac0522b117', '12.6.8.1', 'A localização dos acionadores de rearme deve permitir uma visualização completa da área protegida pelo cabo.', 73),
  ('2713f2d7-cf85-56d2-a418-6e36ee41a7b4', '12000000-0000-0000-0001-000000000007', null, '12.7.1', 'Devem ser adotadas medidas adicionais de proteção das mangueiras, tubulações e demais componentes pressurizados sujeitos a eventuais impactos mecânicos e outros agentes agressivos, quando houver risco.', 74),
  ('7566b725-2a36-52be-9c5c-6f7016097708', '12000000-0000-0000-0001-000000000007', null, '12.7.2', 'As mangueiras, tubulações e demais componentes pressurizados devem ser localizados ou protegidos de tal forma que uma situação de ruptura destes componentes e vazamentos de fluidos não possa ocasionar acidentes de trabalho.', 75),
  ('84c050b6-0581-596e-83cb-2c2508b21888', '12000000-0000-0000-0001-000000000007', null, '12.7.3', 'As mangueiras utilizadas nos sistemas pressurizados devem possuir indicação da pressão máxima de trabalho admissível especificada pelo fabricante.', 76),
  ('3bc02d3c-3e1d-5e7e-857f-09face2ca3fb', '12000000-0000-0000-0001-000000000007', null, '12.7.4', 'Os sistemas pressurizados das máquinas devem possuir meios ou dispositivos destinados a garantir que: a) a pressão máxima de trabalho admissível nos circuitos não possa ser excedida; e b) quedas de pressão progressivas ou bruscas e perdas de vácuo não possam gerar perigo.', 77),
  ('ffa4e17f-686e-5324-8fa0-8fea243e9613', '12000000-0000-0000-0001-000000000007', null, '12.7.5', 'Quando as fontes de energia da máquina forem isoladas, a pressão residual dos reservatórios e de depósitos similares, como os acumuladores hidropneumáticos, não pode gerar risco de acidentes.', 78),
  ('89dfb394-7123-5450-9bbc-e21cc3862044', '12000000-0000-0000-0001-000000000007', null, '12.7.6', 'Os recipientes contendo gases comprimidos utilizados em máquinas e equipamentos devem permanecer em perfeito estado de conservação e funcionamento e ser armazenados em depósitos bem ventilados, protegidos contra quedas, calor e impactos acidentais.', 79),
  ('acbb811f-1b77-5c6e-957c-858fdc112657', '12000000-0000-0000-0001-000000000007', null, '12.7.7', 'Nas atividades de montagem e desmontagem de pneumáticos das rodas das máquinas e equipamentos não estacionários, que ofereçam riscos de acidentes, devem ser observadas as seguintes condições: a) os pneumáticos devem ser completamente despressurizados, removendo o núcleo da válvula de calibragem antes da desmontagem e de qualquer intervenção que possa acarretar acidentes; e b) o enchimento de pneumáticos só poderá se r executado dentro de dispositivo de clausura ou gaiola adequadamente dimensionada, até que seja alcançada uma pressão suficiente para forçar o talão sobre o aro e criar uma vedação pneumática.', 80),
  ('c1eab6e8-e2e9-5642-a645-30b3c156805b', '12000000-0000-0000-0001-000000000007', null, '12.7.8', 'Para fins de aplicação desta NR, consideram -se seguras, não suficientes para provocar danos à integridade física dos trabalhadores, a limitação da força das partes móveis até 150 N (cento e cinquenta Newtons), da pressão de contato até 50 N/cm 2 (cinquenta Newtons por centímetro quadrado) e da energia até 10 J (dez Joules), exceto nos casos em que haja previsão de outros valores em normas técnicas oficiais específicas.', 81),
  ('cb193503-e298-521f-ac9e-cfeb549b3bf8', '12000000-0000-0000-0001-000000000007', 'c1eab6e8-e2e9-5642-a645-30b3c156805b', '12.7.8.1', 'Em sistemas pneumáticos e hidráulicos que utilizam dois ou mais estágios com diferentes pressões como medida de proteção, a força exercida no percurso inicial ou circuito de segurança - aproximação -, a pressão de contato e a energia devem respeitar os limites estabelecidos no subitem 12.7.8, exceto nos casos em que haja previsão de outros valores em normas técnicas oficiais específicas.', 82),
  ('23e57925-10dd-5072-a4fb-c5f859e17755', '12000000-0000-0000-0001-000000000008', null, '12.8.1', 'Os movimentos perigosos dos transportadores contínuos de materiais, acessíveis durante a operação normal, devem ser protegidos, especialmente nos pontos de esmagamento, agarramento e aprisionamento.', 83),
  ('7b6e7760-fcbd-56ec-a190-55038793c931', '12000000-0000-0000-0001-000000000008', '23e57925-10dd-5072-a4fb-c5f859e17755', '12.8.1.1', 'Os transportadores contínuos de correia cuja altura da borda da correia que transporta a carga esteja superior a 2,70 m (dois metros e setenta centímetros) do piso estão dispensados da observância do subitem 12.8.1, desde que não haja circulação nem permanência de pessoas nas zonas de perigo.', 84),
  ('2ef9e711-44fa-58f2-8ee4-61def7c1ec6b', '12000000-0000-0000-0001-000000000008', '23e57925-10dd-5072-a4fb-c5f859e17755', '12.8.1.2', 'Os transportadores contínuos de correia em que haja proteção fixa distante, associada a proteção móvel intertravada que restrinja o acesso a pessoal especializado para a realização de inspeções, manutenções e outras intervenções necessárias, estão dispensados da observância do subitem 12.8.1, desde que atendido o disposto no subitem 12.5.13.', 85),
  ('a48f4344-f94e-5354-8914-2853154aeae0', '12000000-0000-0000-0001-000000000008', null, '12.8.2', 'Os transportadores contínuos de correia, cuja altura da borda da correia que transporta a carga esteja superior a 2,70 m (dois metros e setenta centímetros) do piso, devem possuir, em toda a sua extensão, passarelas em ambos os lados, atendidos os requisitos do item 3 do Anexo III desta NR.', 86),
  ('b25aa796-8f9f-515b-8854-ba58505710ec', '12000000-0000-0000-0001-000000000008', 'a48f4344-f94e-5354-8914-2853154aeae0', '12.8.2.1', 'Os transportadores cuja correia tenha largura de até 762 mm (setecentos e sessenta e dois milímetros) ou 30 (trinta) polegadas podem possuir passarela em apenas um dos lados, devendo -se adotar o uso de plataformas móveis ou elevatórias para quaisquer intervenções e inspeções.', 87),
  ('609780a0-2e41-51aa-9cc5-3a77be5f199a', '12000000-0000-0000-0001-000000000008', 'a48f4344-f94e-5354-8914-2853154aeae0', '12.8.2.2', 'Os transportadores móveis articulados em que haja possibilidade de realização de quaisquer intervenções e inspeções a partir do solo ficam dispensados da exigência do subitem 12.8.2.', 88),
  ('91e916e3-b649-54bb-bc8b-6077e012dda3', '12000000-0000-0000-0001-000000000008', 'a48f4344-f94e-5354-8914-2853154aeae0', '12.8.2.3', 'Ficam dispensados da obrigatoriedade do cumprimento dos subitens 12.8.2 e', 89),
  ('7802e69e-0f7a-5ec9-9efd-e87eb8461f16', '12000000-0000-0000-0001-000000000008', null, '12.8.3', 'Os transportadores de materiais somente devem se r utilizados para o tipo e capacidade de carga para os quais foram projetados.', 90),
  ('d1d0c97d-5c88-52f8-a576-215dee276147', '12000000-0000-0000-0001-000000000008', null, '12.8.4', 'Os cabos de aço, correntes, eslingas, ganchos e outros elementos de suspensão ou tração e suas conexões devem ser adequados ao tipo de material e dimensionados para suportar os esforços solicitantes.', 91),
  ('18a78a1c-2a5e-5fa1-8912-9962abc76ae2', '12000000-0000-0000-0001-000000000008', null, '12.8.5', 'Nos transportadores contínuos de materiais que necessitem de parada durante o processo é proibida a reversão de movimento para esta finalidade.', 92),
  ('d0c1708b-9a54-5346-ae71-8042bf7ce7e1', '12000000-0000-0000-0001-000000000008', null, '12.8.6', 'É proibida a permanência e a circulação de pessoas sobre partes em movimento, ou que possam ficar em movimento, dos transportadores de materiais, quando não projetadas para essas finalidades.', 93),
  ('e3fc953b-5977-56c6-b1d0-bbe6d0114d72', '12000000-0000-0000-0001-000000000008', 'd0c1708b-9a54-5346-ae71-8042bf7ce7e1', '12.8.6.1', 'Nas situações em que haja inviabilidade técnica do cumprimento do disposto no subitem 12.8.6, devem ser adotadas medidas que garantam a paralisação e o bloqueio dos movimentos de risco, conforme o disposto nos subitens 12.11.3 e 12.11.3.1.', 94),
  ('7fa99fd3-e4d6-5956-afec-e9ef22a8113e', '12000000-0000-0000-0001-000000000008', 'd0c1708b-9a54-5346-ae71-8042bf7ce7e1', '12.8.6.2', 'A permanência e a circulação de pessoas sobre os transportadores contínuos devem ser realizadas por meio de passarelas com sistema de proteção contra quedas, conforme item 7 do Anexo III desta NR.', 95),
  ('5c53cbd7-efbb-578d-a8fa-3b8c484b647b', '12000000-0000-0000-0001-000000000008', null, '12.8.7', 'Os transportadores contínuos acessíveis aos trabalhadores devem dispor, ao longo de sua extensão, de dispositivos de parada de emergência, de modo que possam ser acionados em todas as posições de trabalho.', 96),
  ('89a7f018-96b4-50c1-b223-7254dcb0cdfb', '12000000-0000-0000-0001-000000000008', '5c53cbd7-efbb-578d-a8fa-3b8c484b647b', '12.8.7.1', 'Os transportadores contínuos acessíveis aos trabalhadores ficam dispensados do cumprimento da exigência do subitem 12.8.7 se a análise de risco assim indicar.', 97),
  ('c41d2c0d-d28e-556c-8d10-8e955cd2c256', '12000000-0000-0000-0001-000000000008', null, '12.8.8', 'Nos transportadores contínuos de correia cujo desalinhamento anormal da correia ou sobrecarga de materiais ofereçam riscos de acidentes, devem existir dispositivos que garantam a segurança em caso de falha durante sua operação normal e interrompam seu funcionamento quando forem ultrapassados os limites de segurança, conforme especificado em projeto.', 98),
  ('4630d365-591c-530e-84e9-6e5123ec339e', '12000000-0000-0000-0001-000000000008', null, '12.8.9', 'Durante o transporte de materiais suspensos, devem ser adotadas medidas de segurança visando a garantir que não haja pessoas sob a carga.', 99),
  ('46cd7c39-5ab2-5a2b-8877-e988147fec93', '12000000-0000-0000-0001-000000000008', '4630d365-591c-530e-84e9-6e5123ec339e', '12.8.9.1', 'As medidas de segurança previstas no subitem 12.8.9 devem priorizar a existência de áreas exclusivas para a circulação de cargas suspensas devidamente delimitadas e sinalizadas.', 100),
  ('970baca0-260e-5ded-bd3b-b91485547381', '12000000-0000-0000-0001-000000000008', '4630d365-591c-530e-84e9-6e5123ec339e', '12.8.9.2', 'É permitida a permanência e a circulação de pessoas sob os transportadores contínuos somente em locais protegidos que ofereçam resistência e dimensões adequadas contra quedas de materiais.', 101),
  ('5631b621-9624-551d-898b-70d0ee8943bf', '12000000-0000-0000-0001-000000000008', '970baca0-260e-5ded-bd3b-b91485547381', '12.8.9.2.1', 'No transporte de materiais por meio de teleférico dentro da unidade fabril, é permitida a circulação de pessoas, devendo ser adotadas medidas de segurança que garantam a não permanência de trabalhadores sob a carga.', 102),
  ('2c89dc59-f572-529a-97c2-c12c0da98f6b', '12000000-0000-0000-0001-000000000008', '4630d365-591c-530e-84e9-6e5123ec339e', '12.8.9.3', 'No transporte de materiais por meio de teleférico em área que não seja de propriedade ou domínio da empresa, fica dispensada a obrigação dos subitens 12.8.9,', 103),
  ('534aed54-d269-552f-adc4-46236160498e', '12000000-0000-0000-0001-000000000009', null, '12.9.1', 'Para o trabalho em máquinas e equipamentos devem ser respeitadas as disposições contidas na Norma Regulamentadora n.º 17 - Ergonomia.', 104),
  ('87aedaac-e054-57dc-9e6e-f1731c5c653d', '12000000-0000-0000-0001-000000000009', null, '12.9.2', 'Com relação aos aspectos ergonômicos, as máquinas e equipamentos nacionais ou importadas fabricadas a partir da vigência deste item devem ser projetadas e construídas de modo a atender às disposições das normas técnicas oficiais ou normas técnicas internacionais aplicáveis.', 105),
  ('ce0fe880-eea2-55cd-ba89-24263cee179d', '12000000-0000-0000-0001-000000000010', null, '12.10.1', 'Para fins de aplicação desta NR, devem ser considerados os seguintes riscos adicionais: a) substâncias perigosas quaisquer, sejam agentes biológicos ou agentes químicos em estado sólido, líquido ou gasoso, que apresentem riscos à saúde ou integridade física dos trabalhadores por meio de inalação, ingestão ou contato com a pele, olhos ou mucosas; b) radiações ionizantes geradas pelas máquinas e equipamentos ou provenientes de substâncias radiativas por eles utilizadas, processadas ou produzidas; c) radiações não ionizantes com potencial de causar danos à saúde ou integridade física dos trabalhadores; d) vibrações; e) ruído; f) calor; g) combustíveis, inflamáveis, explosivos e substâncias que reagem perigosamente; e h) superfícies aquecidas acessíveis que apresentem risco de queimaduras causadas pelo contato com a pele.', 106),
  ('b013c5bb-e7f3-5985-8fa2-78fd2f7c1226', '12000000-0000-0000-0001-000000000010', null, '12.10.2', 'Devem ser adotadas medidas de controle dos riscos adicionais provenientes da emissão ou liberação de agentes químicos, físicos e biológicos pelas máquinas e equipamentos, com prioridade à sua eliminação, redução de sua emissão ou liberação e redução da exposição dos trabalhadores, conforme Norma Regulamentadora nº 9 - Avaliação e controle das exposições ocupacionais a agentes físicos, químicos e biológicos. (Alterado pela Portaria MTP nº 806, de 13 de abril de 2022)', 107),
  ('0f17d074-269c-56f1-bcd4-2b06f7564706', '12000000-0000-0000-0001-000000000010', null, '12.10.3', 'As máquinas e equipamentos que utilizem, processem ou produzam combustíveis, inflamáveis, explosivos ou substâncias que reagem perigosamente devem oferecer medidas de proteção contra sua emissão, liberação, combustão, explosão e reação acidentais, bem como a ocorrência de incêndio.', 108),
  ('28064f24-963d-5f8a-86a9-6767c6584608', '12000000-0000-0000-0001-000000000010', null, '12.10.4', 'Devem ser adotadas medidas de proteção contra queimaduras causadas pelo contato da pele com superfícies aquecidas de máquinas e equipamentos, tais como a redução da temperatura superficial, isolação com materiais apropriados e barreiras, sempre que a temperatura da superfície for maior do que o limiar de queimaduras do material do qual é constituída, para um determinado período de contato.', 109),
  ('f55d3884-96db-5b30-a9da-8239ce534ab4', '12000000-0000-0000-0001-000000000011', null, '12.11.1', 'As máquinas e equipamentos devem ser submetidos a manutenções na forma e periodicidade determinada pelo fabricante, por profissional legalmente habilitado ou por profissional qualificado, conforme as normas técnicas oficiais ou normas técnicas internacionais aplicáveis.', 110),
  ('27b08f78-9ef0-5ff3-815e-09ae2181425a', '12000000-0000-0000-0001-000000000011', null, '12.11.2', 'As manutenções devem ser registradas em livro próprio, ficha ou sistema informatizado interno da empresa, com os seguintes dados: a) intervenções realizadas; b) data da realização de cada intervenção; c) serviço realizado; d) peças reparadas ou substituídas; e) condições de segurança do equipamento; f) indicação conclusiva quanto às condições de segurança da máquina; e g) nome do responsável pela execução das intervenções.', 111),
  ('9234d987-f8b0-533c-aa79-6bc5a6f861fe', '12000000-0000-0000-0001-000000000011', '27b08f78-9ef0-5ff3-815e-09ae2181425a', '12.11.2.1', 'O registro das manutenções deve ficar disponível aos trabalhadores envolvidos na operação, manutenção e reparos, bem como à Comissão Interna de Prevenção de Acidentes e de Assédio - CIPA, ao Serviço de Segurança e Medicina do Trabalho - SESMT e à Auditoria Fiscal do Trabalho. (Alterado pela Portaria MTP nº 4.219, de 20 de dezembro de 2022)', 112),
  ('35656bb0-fe61-5877-9c80-cbcf66c9a490', '12000000-0000-0000-0001-000000000011', '27b08f78-9ef0-5ff3-815e-09ae2181425a', '12.11.2.2', 'As manutenções de itens que influenciem na segurança devem: a) no caso de preventivas, possuir cronograma de execução; b) no caso de preditivas, possuir descrição das técnicas de análise e meios de supervisão centralizados ou de amostragem.', 113),
  ('e964476b-d305-59b0-9092-212118851430', '12000000-0000-0000-0001-000000000011', null, '12.11.3', 'A manutenção, inspeção, reparos, limpeza, ajuste e outras intervenções que se fizerem necessárias devem ser executadas por profissionais capacitados, qualificados ou legalmente habilitados, formalmente autorizados pelo empregador, com as máquinas e equipamentos parados e adoção dos seguintes procedimentos: a) isolamento e descarga de todas as fontes de energia das máquinas e equipamentos, de modo visível ou facilmente identificável por meio dos dispositivos de comando; b) bloqueio mecânico e elétrico na posição “desligado” ou “fechado” de todos os dispositivos de corte de fontes de energia, a fim de impedir a reenergização, e sinalização com cartão ou etiqueta de bloqueio contendo o horário e a data do bloqueio, o motivo da manutenção e o nome do responsável; c) medidas que garantam que à jusante dos pontos de corte de energia não exista possibilidade de gerar risco de acidentes; d) medidas adicionais de segurança, quando for realizada manutenção, inspeção e reparos de máquinas ou equipamentos sustentadas somente por sistemas hidráulicos e pneumáticos; e e) sistemas de retenção com trava mecânica, para evitar o movimento de retorno acidental de partes basculadas ou articuladas abertas das máquinas e equipamentos.', 114),
  ('45792ab1-fb1d-5c8e-91ae-9e570702670b', '12000000-0000-0000-0001-000000000011', 'e964476b-d305-59b0-9092-212118851430', '12.11.3.1', 'Para situações especiais de manutenção, regulagem, ajuste, limpeza, pesquisa de defeitos e inconformidades, em que não seja possível o cumprimento das condições estabelecidas no subitem 12.11.3, e em outras situações que impliquem a redução do nível de segurança das máquinas e equipamentos e houver necessidade de acesso às zonas de perigo, deve ser possível selecionar um modo de operação que: a) torne inoperante o modo de comando automático; b) permita a realização dos serviços com o uso de dispositivo de acionamento de ação continuada associado à redução da velocidade, ou dispositivos de comando por movimento limitado; c) impeça a mudança por trabalhadores não autorizados; d) a seleção corresponda a um único modo de comando ou de funcionamento; e) quando selecionado, tenha prioridade sobre todos os outros sistemas de comando, com exceção da parada de emergência; e f) torne a seleção visível, clara e facilmente identificável.', 115),
  ('3efda98d-6a74-5a26-a230-114981111ddf', '12000000-0000-0000-0001-000000000011', 'e964476b-d305-59b0-9092-212118851430', '12.11.3.2', 'Ficam dispensadas do atendimento dos subitens 12.11.3 e 12.11.3.1, as situações especiais de manutenção, regulagem, ajuste, pesquisa de defeitos e inconformidades que não ofereçam riscos às pessoas envolvidas na realização destas atividades, que não impliquem na redução do nível de segurança e que não necessitem de acesso às zonas de perigo, desde que executadas sob supervisão do empregador ou pessoa por ele designada.', 116),
  ('7b03de9a-2150-5f5d-9f06-9f705a07d8bd', '12000000-0000-0000-0001-000000000011', 'e964476b-d305-59b0-9092-212118851430', '12.11.3.3', 'Na impossibilidade técnica da aplicação das medidas dos subitens 12.11.3 e 12.11.3.1, em função de inércia térmica do processo, podem ser adotadas outras medidas de segurança, desde que sejam planejadas e gerenciadas por profissional legalmente habilitado e resguardem a segurança e a saúde dos trabalhadores.', 117),
  ('8771f1f7-6367-520d-8c37-d714d966b253', '12000000-0000-0000-0001-000000000011', null, '12.11.4', 'A manutenção de máquinas e equipamentos contemplará, quando indicado pelo fabricante, dentre outros itens, a realização de Ensaios Não Destrutivos - ENDs, nas estruturas e componentes submetidos a solicitações de força e cuja ruptura ou desgaste possa ocasionar acidentes.', 118),
  ('98ea20f4-4051-5f0d-a2bd-00eb8270bc73', '12000000-0000-0000-0001-000000000011', '8771f1f7-6367-520d-8c37-d714d966b253', '12.11.4.1', 'Os ENDs, quando realizados, devem atender às normas técnicas oficiais ou normas técnicas internacionais aplicáveis.', 119),
  ('086622de-347e-5616-bea2-b72c5d6c55a1', '12000000-0000-0000-0001-000000000011', null, '12.11.5', 'Nas manutenções das máquinas e equipamentos, sempre que detectado qualquer defeito em peça ou componente que comprometa a segurança, deve ser providenciada sua reparação ou substituição imediata por outra peça ou componente original ou equivalente, de modo a garantir as mesmas características e condições seguras de uso.', 120),
  ('458479c4-f61e-56f2-9452-981e7071b10b', '12000000-0000-0000-0001-000000000012', null, '12.12.1', 'As máquinas e equipamentos, bem como as instalações em que se encontram, devem possuir sinalização de segurança para advertir os trabalhadores e terceiros sobre os riscos a que estão expostos, as instruções de operação e manutenção e outras informações necessárias para garantir a integridade física e a saúde dos trabalhadores.', 121),
  ('1f1c664f-01e3-5a3a-a3df-d77b55d37169', '12000000-0000-0000-0001-000000000012', '458479c4-f61e-56f2-9452-981e7071b10b', '12.12.1.1', 'A sinalização de segurança compreende a utilização de cores, símbolos, inscrições, sinais luminosos ou sonoros, entre outras formas de comunicação de mesma eficácia.', 122),
  ('229ff5ce-afd6-5ba7-84f0-8c417ea62b12', '12000000-0000-0000-0001-000000000012', '458479c4-f61e-56f2-9452-981e7071b10b', '12.12.1.2', 'A sinalização, inclusive cores, das máquinas e equipamentos utilizados nos setores alimentícios, médico e farmacêutico deve respeitar a legislação sanitária vigente, sem prejuízo da segurança e saúde dos trabalhadores ou terceiros.', 123),
  ('85942e1d-824d-58e9-b167-8bfda03a90b0', '12000000-0000-0000-0001-000000000012', '458479c4-f61e-56f2-9452-981e7071b10b', '12.12.1.3', 'A sinalização de segurança deve ser adotada em todas as fases de utilização e vida útil das máquinas e equipamentos.', 124),
  ('7a238871-d0c9-5b96-ab6f-27e982c5017e', '12000000-0000-0000-0001-000000000012', null, '12.12.2', 'A sinalização de segurança deve: a) ficar destacada na máquina ou equipamento; b) ficar em localização claramente visível; e c) ser de fácil compreensão.', 125),
  ('fb275fd9-8392-5f71-b6fa-195244fb8551', '12000000-0000-0000-0001-000000000012', null, '12.12.3', 'Os símbolos, inscrições e sinais luminosos e sonoros devem seguir os padrões estabelecidos pelas normas técnicas oficiais ou pelas normas técnicas internacionais aplicáveis.', 126),
  ('e42c8dfa-7435-5907-89ae-314d50b08739', '12000000-0000-0000-0001-000000000012', null, '12.12.4', 'As inscrições das máquinas e equipamentos devem: a) ser escritas na língua portuguesa (Brasil); e b) ser legíveis.', 127),
  ('2e9fb162-1f17-5342-97d9-9781429cf70f', '12000000-0000-0000-0001-000000000012', 'e42c8dfa-7435-5907-89ae-314d50b08739', '12.12.4.1', 'As inscrições devem indicar claramente o risco e a parte da máquina ou equipamento a que se referem, e não deve ser utilizada somente a inscrição de “perigo”.', 128),
  ('cfff80d3-a0fc-5ef8-b80e-f716b99fb8bc', '12000000-0000-0000-0001-000000000012', null, '12.12.5', 'As inscrições e símbolos devem ser utilizados nas máquinas e equipamentos para indicar as suas especificações e limitações técnicas fundamentais à segurança.', 129),
  ('6df13ee4-254c-5598-8306-b642880a3a0f', '12000000-0000-0000-0001-000000000012', null, '12.12.6', 'Devem ser adotados, sempre que necessário, sinais ativos de aviso ou de alerta, tais como sinais luminosos e sonoros intermitentes, que indiquem a iminência ou a ocorrência de um evento perigoso, como a partida, a parada ou a velocidade excessiva de uma máquina ou equipamento, de modo que: a) não sejam ambíguos; e b) possam ser inequivocamente reconhecidos pelos trabalhadores.', 130),
  ('048688ac-a130-5ad6-b9ef-e960f9ed0937', '12000000-0000-0000-0001-000000000012', null, '12.12.7', 'As máquinas e equipamentos fabricados a partir de 24 de dezembro de 2011 devem possuir em local visível as seguintes informações indeléveis: a) razão social, CNPJ e endereço do fabricante ou importador; b) informação sobre tipo, modelo e capacidade; c) número de série ou identificação, e ano de fabricação; d) número de registro do fabricante/importador ou do profissional legalmente habilitado no Conselho Regional de Engenharia e Agronomia - CREA; e e) peso da máquina ou equipamento.', 131),
  ('47d5c29a-cdaf-5b39-96b2-098ac6c99aa4', '12000000-0000-0000-0001-000000000012', '048688ac-a130-5ad6-b9ef-e960f9ed0937', '12.12.7.1', 'As máquinas e equipamentos fabricados antes de 24 de dezembro de 2011 devem possuir em local visível as seguintes informações: a) informação sobre tipo, modelo e capacidade; b) número de série ou, quando inexistente, identificação atribuída pela empresa.', 132),
  ('5c389d0e-4fd0-5539-8abb-5477c3e62c4b', '12000000-0000-0000-0001-000000000012', null, '12.12.8', 'Para advertir os trabalhadores sobre os possíveis perigos, devem ser instalados dispositivos indicadores, se necessária a leitura qualitativa ou quantitativa para o controle de segurança.', 133),
  ('f2bf895c-ad47-5ee2-867f-6784e69b968f', '12000000-0000-0000-0001-000000000012', '5c389d0e-4fd0-5539-8abb-5477c3e62c4b', '12.12.8.1', 'Os indicadores devem ser de fácil leitura e distinguíveis uns dos outros.', 134),
  ('9ca3ee3e-7a0b-5ef4-8889-6bc3ea448186', '12000000-0000-0000-0001-000000000013', null, '12.13.1', 'As máquinas e equipamentos devem possuir manual de instruções fornecido pelo fabricante ou importador, com informações relativas à segurança em todas as fases de utilização.', 135),
  ('514d3ace-b92f-5195-b777-3b305675aa94', '12000000-0000-0000-0001-000000000013', null, '12.13.2', 'Os manuais devem: a) ser escritos na língua portuguesa (Brasil), com caracteres de tipo e tamanho que possibilitem a melhor legibilidade possível, acompanhado das ilustrações explicativas; b) ser objetivos, claros, sem ambiguidades e em linguagem de fácil compreensão; c) ter sinais ou avisos referentes à segurança realçados; e d) permanecer disponíveis a todos os usuários nos locais de trabalho.', 136),
  ('e5d281c0-8d74-5c21-a662-0667de07570a', '12000000-0000-0000-0001-000000000013', null, '12.13.3', 'Os manuais de máquinas e equipamentos, nacionais ou importados, fabricadas a partir da vigência deste item, devem seguir as normas técnicas oficiais ou internacionais aplicáveis.', 137),
  ('341e6cf6-2eec-5533-b8ac-ce6394e9f38e', '12000000-0000-0000-0001-000000000013', null, '12.13.4', 'Os manuais das máquinas e equipamentos fabricados ou importados entre 24 de junho de 2012 e a data de entrada em vigor deste item devem conter, no mínimo, as seguintes informações: a) razão social, CNPJ e endereço do fabricante ou importador; b) tipo, modelo e capacidade; c) número de série ou número de identificação e ano de fabricação; d) normas observadas para o projeto e construção da máquina ou equipamento; e) descrição detalhada da máquina ou equipamento e seus acessórios; f) diagramas, inclusive circuitos elétricos, em especial a representação esquemática das funções de segurança; g) definição da utilização prevista para a máquina ou equipamento; h) riscos a que estão expostos os usuários, com as respectivas avaliações quantitativas de emissões geradas pela máquina ou e quipamento em sua capacidade máxima de utilização; i) definição das medidas de segurança existentes e daquelas a serem adotadas pelos usuários; j) especificações e limitações técnicas para a sua utilização com segurança; k) riscos que podem resultar de adulteração ou supressão de proteções e dispositivos de segurança; l) riscos que podem resultar de utilizações diferentes daquelas previstas no projeto; m) informações técnicas para subsidiar a elaboração dos procedimentos de trabalho e segurança durante todas as fases de utilização; n) procedimentos e periodicidade para inspeções e manutenção; o) procedimentos a serem adotados em situações de emergência; e p) indicação da vida útil da máquina ou equipamento e/ou dos componentes relacionados com a segurança.', 138),
  ('97be8bb8-214d-5db8-b1a6-3f62d5eee7a2', '12000000-0000-0000-0001-000000000013', null, '12.13.5', 'Quando inexistente ou extraviado, o manual de máquinas ou equipamentos que apresentem riscos deve ser reconstituído pelo empregador ou pessoa por ele designada, sob a responsabilidade de profissional qualificado ou legalmente habilitado.', 139),
  ('c59a7c02-581a-5af7-b64e-54f03f9c8b64', '12000000-0000-0000-0001-000000000013', '97be8bb8-214d-5db8-b1a6-3f62d5eee7a2', '12.13.5.1', 'Em caso de manuais reconstituídos, estes devem conter as informações previstas nas alíneas “b”, “e”, “g”, “i”, “j”, “k”, “m”, “n” e “o” do subitem 12.13.4, bem como diagramas de sistemas de segurança e diagrama unifilar ou trifilar do sistema elétrico, conforme o caso.', 140),
  ('13a75f6e-bc14-5eea-92a0-c5bd24fde763', '12000000-0000-0000-0001-000000000013', '97be8bb8-214d-5db8-b1a6-3f62d5eee7a2', '12.13.5.2', 'No caso de máquinas e equipamentos cujos fabricantes não estão mais em atividade, a alínea “j” do subitem 12.13.4 poderá ser substituída pelo procedimento previsto no subitem 12.14.1, contemplados os limites da máquina.', 141),
  ('52f330d1-013d-545e-a470-dde8a4ee0c2f', '12000000-0000-0000-0001-000000000013', '97be8bb8-214d-5db8-b1a6-3f62d5eee7a2', '12.13.5.3', 'As microempresas e empr esas de pequeno porte que não disponham de manual de instruções de máquinas e equipamentos fabricados antes de 24 de junho de 2012 devem elaborar ficha de informação contendo os seguintes itens: a) tipo, modelo e capacidade; b) descrição da utilização prevista para a máquina ou equipamento; c) indicação das medidas de segurança existentes; d) instruções para utilização segura da máquina ou equipamento; e) periodicidade e instruções quanto às inspeções e manutenção; f) procedimentos a serem adotados em situações de emergência, quando aplicável.', 142),
  ('d0b29836-64c2-58a6-8476-6742dd134961', '12000000-0000-0000-0001-000000000013', '52f330d1-013d-545e-a470-dde8a4ee0c2f', '12.13.5.3.1', 'A ficha de informação indicada no subitem 12.13.5.3 pode ser elaborada pelo empregador ou pessoa designada por este.', 143),
  ('e8d57715-cf40-557a-83ed-bb03c903ce21', '12000000-0000-0000-0001-000000000014', null, '12.14.1', 'Devem ser elaborados procedimentos de trabalho e segurança para máquinas e equipamentos, específicos e padronizados, a partir da apreciação de riscos.', 144),
  ('d6cc4d22-737b-535f-9e2b-7e6117661cc6', '12000000-0000-0000-0001-000000000014', 'e8d57715-cf40-557a-83ed-bb03c903ce21', '12.14.1.1', 'Os procedimentos de trabalho e segurança não podem ser as únicas medidas de proteção adotadas para se prevenir acidentes, sendo considerados complementos e não substitutos das medidas de proteção coletivas necessárias para a garantia da segurança e saúde dos trabalhadores.', 145),
  ('15cf78a4-5217-5c91-be62-3841010879ac', '12000000-0000-0000-0001-000000000014', null, '12.14.2', 'Ao início de cada turno de trabalho ou após nova preparação da máquina ou equipamento, o operador deve efetuar inspeção rotineira das condições de operacionalidade e segurança e, se constatadas anormalidades que afetem a segurança, as atividades devem ser interrompidas, com a comunicação ao superior hierárquico.', 146),
  ('5992589c-47f4-5b9a-97b1-5b76484c28c1', '12000000-0000-0000-0001-000000000014', '15cf78a4-5217-5c91-be62-3841010879ac', '12.14.2.1', 'Não é obrigatório o registro em livro próprio, ficha ou sistema informatizado da inspeção rotineira realizada pelo operador prevista no subitem 12.14.2.', 147),
  ('6ad16ad0-ef77-53b7-b055-f96fa957c600', '12000000-0000-0000-0001-000000000014', null, '12.14.3', 'Os serviços que envolvam risco de acidentes de trabalho em máquinas e equipamentos, exceto operação, devem ser planejados e realizados em conformidade com os procedimentos de trabalho e segurança, sob supervisão e anuência expressa de profissional habilitado ou qualificado, desde que autorizados.', 148),
  ('62d8d063-fde6-5e9b-8dcf-f9e72189f43f', '12000000-0000-0000-0001-000000000014', '6ad16ad0-ef77-53b7-b055-f96fa957c600', '12.14.3.1', 'As empresas que não possuem serviço próprio de manutenção de suas máquinas ficam desobrigadas de elaborar procedimentos de trabalho e segurança para essa finalidade.', 149),
  ('85532b4d-d6c9-560f-bb9c-a42a677ad435', '12000000-0000-0000-0001-000000000015', null, '12.15.1', 'O projeto das máquinas e equipamentos fabricados a partir da publicação da Portaria SIT n.º 197, de 17 de dezembro de 2010, D.O.U. de 24 de dezembro de 2010, deve levar em conta a segurança intrínseca da máquina ou equipamento durante as fases de construção, transporte, montagem, instalação, ajuste, operação, limpeza, manutenção, inspeção, desativação, desmonte e sucateamento por meio das referências técnicas, a serem observadas para resguardar a saúde e a integridade física dos trabalhadores.', 150),
  ('423a4ddb-7099-5784-b68b-44f4c2184f62', '12000000-0000-0000-0001-000000000015', '85532b4d-d6c9-560f-bb9c-a42a677ad435', '12.15.1.1', 'O projeto da máquina ou equipamento não deve permitir erros na montagem ou remontagem de determinadas peças ou elementos que possam gerar riscos durante seu funcionamento, especialmente quanto ao sentido de rotação ou deslocamento.', 151),
  ('2054f0ed-9751-531a-9ff2-55ebf0a7e775', '12000000-0000-0000-0001-000000000015', '85532b4d-d6c9-560f-bb9c-a42a677ad435', '12.15.1.2', 'O projeto das máquinas ou equipamentos fabricados ou importados após a vigência desta NR deve prever meios adequados para o seu levantamento, carregamento, instalação, remoção e transporte.', 152),
  ('d6003ada-391f-5739-9127-6fecb8412702', '12000000-0000-0000-0001-000000000015', '85532b4d-d6c9-560f-bb9c-a42a677ad435', '12.15.1.3', 'Devem ser previstos meios seguros para as atividades de instalação, remoção, desmonte ou transporte, mesmo que em partes, de máquinas e equipamentos fabricados ou importados antes da vigência desta NR.', 153),
  ('9b09c323-0a6d-5b8c-b026-51e43d1df0b6', '12000000-0000-0000-0001-000000000015', null, '12.15.2', 'É proibida a fabricação, importação, comercialização, leilão, locação, cessão a qualquer título e exposição de máquinas e equipamentos que não atendam ao disposto nesta NR.', 154),
  ('ac864cfb-986a-56f9-8aff-17c377b405c0', '12000000-0000-0000-0001-000000000016', null, '12.16.1', 'A operação, manutenção, inspeção e demais intervenções em máquinas e equipamentos devem ser realizadas por trabalhadores habilitados ou qualificados ou capacitados, e autorizados para este fim.', 155),
  ('44fed3a6-74f5-5bab-8664-a68da6798bd6', '12000000-0000-0000-0001-000000000016', null, '12.16.2', 'Os trabalhadores envolvidos na operação, manutenção, inspeção e demais intervenções em máquinas e equipamentos devem receber capacitação providenciada pelo empregador e compatível com suas funções, que aborde os riscos a que estão expostos e as medidas de proteção existentes e necessárias, nos termos desta NR, para a prevenção de acidentes e doenças.', 156),
  ('4c92d28d-4907-505a-b9ba-90967ac9fd89', '12000000-0000-0000-0001-000000000016', null, '12.16.3', 'A capacitação deve: a) ocorrer antes que o trabalhador assuma a sua função; b) ser realizada sem ônus para o trabalhador; c) ter carga horária mínima, definida pelo empregador, que garanta aos trabalhadores executarem suas atividades com segurança, sendo realizada durante a jornada de trabalho; d) ter conteúdo programático conforme o estabelecido no Anexo II desta NR; e e) ser ministrada por trabalhadores ou profissionais ou qualificados para este fim, com supervisão de profissional legalmente habilitado que se responsabilizará pela adequação do conteúdo, forma, carga horária, qualificação dos instrutores e avaliação dos capacitados.', 157),
  ('056fabfd-4902-5e1e-ae30-a160b439d57a', '12000000-0000-0000-0001-000000000016', '4c92d28d-4907-505a-b9ba-90967ac9fd89', '12.16.3.1', 'A capacitação dos trabalh adores de microempresas e empresas de pequeno porte poderá ser ministrada por trabalhador da própria empresa que tenha sido capacitado nos termos do subitem 12.16.3 em entidade oficial de ensino de educação profissional.', 158),
  ('57c6eed8-cc63-58dd-8379-0be2cae43916', '12000000-0000-0000-0001-000000000016', '056fabfd-4902-5e1e-ae30-a160b439d57a', '12.16.3.1.1', 'O empregador é responsável pela capacitação realizada nos termos do subitem 12.16.3.1.', 159),
  ('18bb4405-4714-523d-9703-5b3eaf88c84f', '12000000-0000-0000-0001-000000000016', '056fabfd-4902-5e1e-ae30-a160b439d57a', '12.16.3.1.2', 'A capacitação dos trabalhadores de microempresas e empresas de pequeno porte, prevista no subitem 12.16.3.1, deve contemplar o disposto no subitem 12.16.3, exceto a alínea “e”.', 160),
  ('c647a9d8-9f30-5027-b3c5-3c69c8d356da', '12000000-0000-0000-0001-000000000016', '4c92d28d-4907-505a-b9ba-90967ac9fd89', '12.16.3.2', 'É considerado capacitado o trabalhador de microempresa e empresa de pequeno porte que apresentar declaração ou certificado emitido por entidade oficial de ensino de educação profissional, desde que atenda o disposto no subitem 12.16.3.', 161),
  ('eef349a9-2a94-5cc2-ae96-6bd03778fc48', '12000000-0000-0000-0001-000000000016', null, '12.16.4', 'O material didático escrito ou audiovisual utilizado no treinamento, fornecido aos participantes, deve ser produzido em linguagem adequada aos trabalhadores.', 162),
  ('1ab0fa6d-3bc7-5a4d-9c5e-92219752c442', '12000000-0000-0000-0001-000000000016', null, '12.16.5', 'O material didático fornecido aos trabalhadores, a lista de presença dos participantes ou certificado, o currículo dos ministrantes e a avaliação dos capacitados devem ser disponibilizados à Auditoria Fiscal do Trabalho em meio físico ou digital, quando solicitado.', 163),
  ('0b8b4dbc-847f-5229-85b4-5434a7444f95', '12000000-0000-0000-0001-000000000016', null, '12.16.6', 'A capacitação só terá validade para o empregador que a realizou e nas condições estabelecidas pelo profissional legalmente habilitado responsável pela supervisão da capacitação, exceto quanto aos trabalhadores capacitados nos termos do subitem 12.16.3.2.', 164),
  ('b0089180-7e40-5719-9a5c-ae10f316f195', '12000000-0000-0000-0001-000000000016', '0b8b4dbc-847f-5229-85b4-5434a7444f95', '12.16.6.1', 'Fica dispensada a exigência do subitem 12.16.6 para os operadores de injetoras com curso de capacitação conforme o previsto no subitem 12.16.11 e seus subitens.', 165),
  ('6660294b-344b-5480-b4d8-bc15488674ae', '12000000-0000-0000-0001-000000000016', null, '12.16.7', 'Até a data da vigência desta NR, será considerado capacitado o trabalhador que possuir comprovação por meio de registro na Carteira de Trabalho e Previdência Social - CTPS ou registro de empregado de pelo menos dois anos de experiência na atividade e que receba reciclagem conforme o previsto no subitem 12.16.8 desta NR.', 166),
  ('95d8de6e-6967-5937-956b-35d84080b671', '12000000-0000-0000-0001-000000000016', null, '12.16.8', 'Deve ser realizada capacitação para reciclagem do trabalhador sempre que ocorrerem modificações significativas nas instalações e na operação de máquinas ou troca de métodos, processos e organização do trabalho, que impliquem em novos riscos.', 167),
  ('2b02f8c7-c074-51a9-8c42-2bff95181d1c', '12000000-0000-0000-0001-000000000016', '95d8de6e-6967-5937-956b-35d84080b671', '12.16.8.1', 'O conteúdo programático da capacitação para reciclagem deve atender às necessidades da situação que a motivou, com carga horária mínima, definida pelo empregador e dentro da jornada de trabalho.', 168),
  ('1259b1cf-13e5-51a9-bbb8-5dee199b4b01', '12000000-0000-0000-0001-000000000016', null, '12.16.9', 'A função do trabalhador que opera e realiza intervenções em máquinas deve ser anotada no registro de empregado, consignado em livro, ficha ou sistema eletrônico e em sua CTPS.', 169),
  ('110fb709-8d1a-5788-b070-341cfe2d0e09', '12000000-0000-0000-0001-000000000016', null, '12.16.10', 'Os operadores de máquinas autopropelidas devem portar cartão de identificação, com nome, função e fotografia em local visível, renovado com periodicidade máxima de um ano mediante exame médico, conforme disposições constantes da Norma Regulamentadora n.º 07 - Programa de Controle Médico de Saúde Ocupacional - PCMSO e na Norma Regulamentadora n.º 11 - Transporte, Movimentação, Armazenagem e Manuseio de Materiais.', 170),
  ('da68c3c6-05e8-5508-9caa-8e1e89ba20b8', '12000000-0000-0000-0001-000000000016', null, '12.16.11', 'O curso de capacitação para operadores de máquinas injetoras deve possuir carga horária mínima de oito horas por tipo de máquina citada no Anexo IX desta NR.', 171),
  ('260c58e6-0d88-54bb-9643-3233358c744b', '12000000-0000-0000-0001-000000000016', 'da68c3c6-05e8-5508-9caa-8e1e89ba20b8', '12.16.11.1', 'O curso de capacitação deve ser específico para o tipo máquina em que o operador irá exercer suas funções e atender ao seguinte conteúdo programático: a) histórico da regulamentação de segurança sobre a máquina especificada; b) descrição e funcionamento; c) riscos na operação; d) principais áreas de perigo; e) medidas e dispositivos de segurança para evitar acidentes; f) proteções - portas, e distâncias de segurança; g) exigências mínimas de segurança previstas nesta NR e na Norma Regulamentadora n.º 10 - Segurança em Instalações e Serviços em Eletricidade; h) medidas de segurança para injetoras elétricas e hidráulicas de comando manual; e i) demonstração prática dos perigos e dispositivos de segurança.', 172),
  ('ab188d9b-6361-53bf-82f6-32aefe00f023', '12000000-0000-0000-0001-000000000016', 'da68c3c6-05e8-5508-9caa-8e1e89ba20b8', '12.16.11.2', 'O instrutor do curso de capacitação para operadores de injetora deve, no mínimo, possuir: a) formação técnica em nível médio; b) conhecimento técnico de máquinas utilizadas na transformação de material plástico; c) conhecimento da normatização técnica de segurança; e d) capacitação específica de formação.', 173),
  ('722ff372-1d5a-54b6-9d5b-4c68ae38cf3d', '12000000-0000-0000-0001-000000000017', null, '12.17.1', 'As ferramentas e materiais utilizados nas intervenções em máquinas e equipamentos devem ser adequados às operações realizadas.', 174),
  ('34bfd80b-04a9-53be-b894-e8e0649d29c1', '12000000-0000-0000-0001-000000000017', null, '12.17.2', 'Os acessórios e ferramental utilizados pelas máquinas e equipamentos devem ser adequados às operações realizadas.', 175),
  ('f3e80b62-b71e-5935-a9be-ed3515796bae', '12000000-0000-0000-0001-000000000017', null, '12.17.3', 'É proibido o porte de ferramentas manuais em bolsos ou locais não apropriados a essa finalidade.', 176),
  ('53d9c468-c0e1-5a68-9e05-d4e669562d80', '12000000-0000-0000-0001-000000000017', null, '12.17.4', 'As máquinas e equipamentos tracionados devem possuir sistemas de engate padronizado para reboque pelo sistema de tração, de modo a assegurar o acoplamento e desacoplamento fácil e seguro, bem como a impedir o desacoplamento acidental durante a utilização.', 177),
  ('6a1468aa-972e-5d44-82dc-48b057a2022b', '12000000-0000-0000-0001-000000000017', '53d9c468-c0e1-5a68-9e05-d4e669562d80', '12.17.4.1', 'A indicação de uso dos sistemas de engate padronizado mencionados no subitem 12.17.4 deve ficar em local de fácil visualização e afixada em local próximo da conexão.', 178),
  ('51b362b1-4c50-5a68-b934-35d55be7a77c', '12000000-0000-0000-0001-000000000017', '53d9c468-c0e1-5a68-9e05-d4e669562d80', '12.17.4.2', 'Os equipamentos tracionados, caso o peso da barra do reboque assim o exija, devem possuir dispositivo de apoio que possibilite a redução do esforço e a conexão segura ao sistema de tração.', 179),
  ('c7d29b02-fd3d-5195-a94c-5cb864587b1d', '12000000-0000-0000-0001-000000000017', '53d9c468-c0e1-5a68-9e05-d4e669562d80', '12.17.4.3', 'A operação de engate deve ser feita em local apropriado e com o equipamento tracionado imobilizado de forma segura com calço ou similar.', 180),
  ('039b1b68-0e49-539b-bb1c-e6eda3616245', '12000000-0000-0000-0001-000000000017', null, '12.17.5', 'Para fins de aplicação desta NR, os Anexos contemplam obrigações, disposições especiais ou exceções que se aplicam a um determinado tipo de máquina ou equipamento, em caráter prioritário aos demais requisitos desta NR, sem prejuízo ao disposto em NR especifica.', 181),
  ('d0c192b9-18b3-54f5-9774-8dc5cd1593a1', '12000000-0000-0000-0001-000000000017', '039b1b68-0e49-539b-bb1c-e6eda3616245', '12.17.5.1', 'Nas situações onde os itens dos Anexos conflitarem com os itens da parte geral da NR, prevalecem os requisitos do anexo.', 182),
  ('132ce036-873d-5b9b-8934-2396a727cbf0', '12000000-0000-0000-0001-000000000017', '039b1b68-0e49-539b-bb1c-e6eda3616245', '12.17.5.2', 'As obrigações dos anexos desta NR se aplicam exclusivamente às máquinas e equipamentos neles contidas.', 183),
  ('0668464e-fdf5-5eb5-9544-05d313ec327b', '12000000-0000-0000-0001-000000000018', null, '12.18.1', 'O empregador deve manter à disposição da Auditoria-Fiscal do Trabalho relação atualizada das máquinas e equipamentos.', 184),
  ('7829099c-d8b6-5858-b326-e2faa04f36ec', '12000000-0000-0000-0001-000000000018', null, '12.18.2', 'Toda a documentação referida nesta NR deve ficar disponível para CIPA ou Comissão Interna de Prevenção de Acidentes na Mineração - CIPAMIN, sindicatos representantes da categoria profissional e Auditoria Fiscal do Trabalho, apresentado em formato digital ou meio físico.', 185),
  ('dfa90d20-0c46-55c0-9f3d-37a351bde6c9', '12000000-0000-0000-0001-000000000018', null, '12.18.3', 'As máquinas autopropelidas agrícolas, florestais e de construção em aplicações agroflorestais e respectivos implementos devem atender ao disposto no Anexo XI desta NR.', 186),
  ('e15e294a-823b-5c46-be9a-78c357b93ce5', '12000000-0000-0000-0001-000000000018', null, '12.18.4', 'As máquinas autopropelidas não contempladas no item 12.18.3 devem atender ao disposto nos itens e subitens 12.1.1, 12.1.1.1, 12.1.2, 12.1.7, 12.1.8, 12.1.9, 12.1.9.1, 12.3.9, 12.3.10, 12.5.1, 12.5.9, 12.5.9.2, 12.5.10, 12.5.11, 12.5.14, 12.5.15, 12.5.16, 12.7.1, 12.7.2, 12.9.2, 12.10.2, 12.10.3, 12.11.1, 12.11.2, 12.11.5, 12.12.1, 12.12.1.3, 12.12.2, 12.12.3, 12.12.6, 12.14.1, 12.14.1.1, 12.14.2, 12.14.3, 12.15.1, 12.15.1.1, 12.15.1.2, 12.15.1.3, 12.15.2, 12.16.1, 12.16.2, 12.16.3, 12.16.4, 12.16.5, 12.16.6, 12.16.8, 12.16.8.1, 12.16.9, 12.16.10, 12.17.4, 12.17.4.1, 12.17.4.2, 12.17 .4.3, itens e subitens 1, 1.4 e 3 do Anexo III, e itens e subitens 14, 14.1 e 14.2 do Anexo XI, desta NR.', 187)
